  ('social-worker-moex-00391', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某國中發放記名問卷給學生，請他們填寫自己抽菸和喝酒的頻率，結果很多學生填的答案都比實 際情況為低。此為下列何種誤差？', '["隨機誤差", "相關誤差", "系統誤差", "三角誤差"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00392', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '甲、量表僅施測一次，分兩半套分別計分，再計算兩半套間的相關。乙、量表施測一次，交由兩 人評分，計算兩項分數的相關。丙、將同一量表的兩套組題連續於同一團體施測，計算兩項分數 的相關。以上三種測量信度的方法分別為何？', '["交互評分者信度、複本信度、重測信度", "折半信度、複本信度、內部一致性信度", "折半信度、交互評分者信度、複本信度", "折半信度、交互觀察者信度、平行信度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00393', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '當樣本數從100增加到500時，下列敘述何者正確？', '["抽樣分配的標準誤會增加", "抽樣分配的標準誤會降低", "不會影響樣本分配的標準誤", "抽樣分配不會趨近常態分布"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00394', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某學者想邀請校園性騷擾被害者進行研究，下列何種抽樣方法最適當？', '["系統隨機抽樣", "簡單隨機抽樣", "分層隨機抽樣", "立意抽樣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00395', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '對於電話訪問的敘述，下列何者正確？', '["相較於面對面訪問，較不易召募到訪員", "訪問品質較好控制，訪員效應較低", "不容易產生樣本涵蓋誤差", "電話訪問的問卷長度一般以50分鐘為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00396', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '對於觀察方法的敘述，下列何者錯誤？', '["觀察的步驟通常是由集中到開放，以利蒐集到全方位的觀察資料", "進行觀察之前，事先應確定觀察的問題並制定觀察計畫", "研究者選擇一特定時間段，對這段時間發生的事情進行觀察，屬於一種時間抽樣法的聚焦方法", "相較於聚焦式的觀察，封閉式的觀察只針對事先設定的角度和內容進行觀察和量的計算"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00397', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於量化研究假設的敘述，下列何者錯誤？', '["讓研究問題更聚焦", "具有可測量的條件", "對兩個或兩個以上變項之間的關係進行推測性論述", "提升研究的複雜與主觀性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00398', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '社工想了解個案接受服務後自我效能感是否提升，因此使用量表在服務前進行前測，在服務半年 後進行後測。請問下列何者不會對內在效度造成威脅？', '["過程中發生重大事件", "成熟因素", "個案隨機分派", "測量工具品質"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00399', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '為了解一個量表是否具有建構效度（constructvalidity），常用下列何種統計方法分析？', '["相關係數檢定", "變異數分析", "因素分析", "迴歸分析"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00400', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '若我們將某社會福利機構（甲）之志願服務人員當成實驗組，而給予某種同理心訓練課程，同時 又選擇另一機構（乙）的志願服務人員為控制組。在沒有前測的狀況下，若三個月之後，我們發 現甲機構的志願服務人員在同理心量表的平均分數大於乙機構之平均分數，則下列何種因素最可 能威脅此一研究設計之內在效度？', '["統計迴歸趨中效應", "經歷其他事件（歷史效應）", "選樣效應", "測驗效應"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
